  1â†’/**
  2â†’ * Load, validate, and manage ~/.memorytree/config.toml.
  3â†’ * Port of scripts/_config_utils.py
  4â†’ */
  5â†’
  6â†’import { existsSync, readFileSync, writeFileSync, mkdirSync } from 'node:fs'
  7â†’import { homedir } from 'node:os'
  8â†’import { dirname, resolve } from 'node:path'
  9â†’
 10â†’import { parse as parseToml } from 'smol-toml'
 11â†’
 12â†’import { toPosixPath } from '../utils/path.js'
 13â†’
 14â†’// ---------------------------------------------------------------------------
 15â†’// Constants
 16â†’// ---------------------------------------------------------------------------
 17â†’
 18â†’const DEFAULT_HEARTBEAT_INTERVAL = '5m'
 19â†’const DEFAULT_AUTO_PUSH = true
 20â†’const DEFAULT_LOG_LEVEL = 'info'
 21â†’const VALID_LOG_LEVELS: ReadonlySet<string> = new Set(['debug', 'info', 'warn', 'error'])
 22â†’
 23â†’// ---------------------------------------------------------------------------
 24â†’// Types
 25â†’// ---------------------------------------------------------------------------
 26â†’
 27â†’export interface ProjectEntry {
 28â†’  readonly path: string
 29â†’  readonly name: string
 30â†’}
 31â†’
 32â†’export interface Config {
 33â†’  readonly heartbeat_interval: string
 34â†’  readonly watch_dirs: readonly string[]
 35â†’  readonly projects: readonly ProjectEntry[]
 36â†’  readonly auto_push: boolean
 37â†’  readonly log_level: string
 38â†’}
 39â†’
 40â†’// ---------------------------------------------------------------------------
 41â†’// Path helpers
 42â†’// ---------------------------------------------------------------------------
 43â†’
 44â†’export function memorytreeRoot(): string {
 45â†’  return resolve(homedir(), '.memorytree')
 46â†’}
 47â†’
 48â†’export function configPath(): string {
 49â†’  return resolve(memorytreeRoot(), 'config.toml')
 50â†’}
 51â†’
 52â†’// ---------------------------------------------------------------------------
 53â†’// Load / Save
 54â†’// ---------------------------------------------------------------------------
 55â†’
 56â†’export function loadConfig(): Config {
 57â†’  const path = configPath()
 58â†’  if (!existsSync(path)) {
 59â†’    return defaultConfig()
 60â†’  }
 61â†’  let raw: Record<string, unknown>
 62â†’  try {
 63â†’    const text = readFileSync(path, 'utf-8')
 64â†’    raw = parseToml(text) as Record<string, unknown>
 65â†’  } catch {
 66â†’    return defaultConfig()
 67â†’  }
 68â†’  return parseRaw(raw)
 69â†’}
 70â†’
 71â†’export function saveConfig(cfg: Config): void {
 72â†’  const path = configPath()
 73â†’  mkdirSync(dirname(path), { recursive: true })
 74â†’
 75â†’  const lines: string[] = [
 76â†’    `heartbeat_interval = "${cfg.heartbeat_interval}"`,
 77â†’    `auto_push = ${cfg.auto_push ? 'true' : 'false'}`,
 78â†’    `log_level = "${cfg.log_level}"`,
 79â†’  ]
 80â†’
 81â†’  if (cfg.watch_dirs.length > 0) {
 82â†’    const items = cfg.watch_dirs.map(d => `"${d}"`).join(', ')
 83â†’    lines.push(`watch_dirs = [${items}]`)
 84â†’  } else {
 85â†’    lines.push('watch_dirs = []')
 86â†’  }
 87â†’
 88â†’  lines.push('')
 89â†’  for (const project of cfg.projects) {
 90â†’    lines.push('[[projects]]')
 91â†’    lines.push(`path = "${project.path}"`)
 92â†’    if (project.name) {
 93â†’      lines.push(`name = "${project.name}"`)
 94â†’    }
 95â†’    lines.push('')
 96â†’  }
 97â†’
 98â†’  writeFileSync(path, lines.join('\n') + '\n', 'utf-8')
 99â†’}
100â†’
101â†’// ---------------------------------------------------------------------------
102â†’// Interval parsing
103â†’// ---------------------------------------------------------------------------
104â†’
105â†’export function intervalToSeconds(interval: string): number {
106â†’  const match = interval.trim().toLowerCase().match(/^(\d+)\s*(s|m|h)$/)
107â†’  if (!match) {
108â†’    return intervalToSeconds(DEFAULT_HEARTBEAT_INTERVAL)
109â†’  }
110â†’  const value = parseInt(match[1]!, 10)
111â†’  const unit = match[2]!
112â†’  if (value <= 0) {
113â†’    return intervalToSeconds(DEFAULT_HEARTBEAT_INTERVAL)
114â†’  }
115â†’  const multiplier: Record<string, number> = { s: 1, m: 60, h: 3600 }
116â†’  return value * (multiplier[unit] ?? 60)
117â†’}
118â†’
119â†’// ---------------------------------------------------------------------------
120â†’// Project registration
121â†’// ---------------------------------------------------------------------------
122â†’
123â†’export function registerProject(cfg: Config, repoPath: string): Config {
124â†’  const resolved = toPosixPath(resolve(repoPath))
125â†’  for (const entry of cfg.projects) {
126â†’    if (toPosixPath(resolve(entry.path)) === resolved) {
127â†’      return cfg
128â†’    }
129â†’  }
130â†’  const name = resolved.split('/').pop() ?? ''
131â†’  return {
132â†’    ...cfg,
133â†’    projects: [...cfg.projects, { path: resolved, name }],
134â†’  }
135â†’}
136â†’
137â†’// ---------------------------------------------------------------------------
138â†’// Internal helpers
139â†’// ---------------------------------------------------------------------------
140â†’
141â†’function defaultConfig(): Config {
142â†’  return {
143â†’    heartbeat_interval: DEFAULT_HEARTBEAT_INTERVAL,
144â†’    watch_dirs: [],
145â†’    projects: [],
146â†’    auto_push: DEFAULT_AUTO_PUSH,
147â†’    log_level: DEFAULT_LOG_LEVEL,
148â†’  }
149â†’}
150â†’
151â†’function parseRaw(raw: Record<string, unknown>): Config {
152â†’  let interval = raw['heartbeat_interval']
153â†’  if (typeof interval !== 'string' || !isValidInterval(interval)) {
154â†’    interval = DEFAULT_HEARTBEAT_INTERVAL
155â†’  }
156â†’
157â†’  let autoPush = raw['auto_push']
158â†’  if (typeof autoPush !== 'boolean') {
159â†’    autoPush = DEFAULT_AUTO_PUSH
160â†’  }
161â†’
162â†’  let logLevel = raw['log_level']
163â†’  if (typeof logLevel !== 'string' || !VALID_LOG_LEVELS.has(logLevel.toLowerCase())) {
164â†’    logLevel = DEFAULT_LOG_LEVEL
165â†’  }
166â†’  logLevel = (logLevel as string).toLowerCase()
167â†’
168â†’  const watchDirs: string[] = []
169â†’  const rawDirs = raw['watch_dirs']
170â†’  if (Array.isArray(rawDirs)) {
171â†’    for (const d of rawDirs) {
172â†’      if (typeof d === 'string') watchDirs.push(d)
173â†’    }
174â†’  }
175â†’
176â†’  const projects: ProjectEntry[] = []
177â†’  const rawProjects = raw['projects']
178â†’  if (Array.isArray(rawProjects)) {
179â†’    for (const entry of rawProjects) {
180â†’      if (entry !== null && typeof entry === 'object' && !Array.isArray(entry)) {
181â†’        const rec = entry as Record<string, unknown>
182â†’        if (typeof rec['path'] === 'string') {
183â†’          projects.push({
184â†’            path: rec['path'] as string,
185â†’            name: String(rec['name'] ?? ''),
186â†’          })
187â†’        }
188â†’      }
189â†’    }
190â†’  }
191â†’
192â†’  return {
193â†’    heartbeat_interval: interval as string,
194â†’    watch_dirs: watchDirs,
195â†’    projects,
196â†’    auto_push: autoPush as boolean,
197â†’    log_level: logLevel as string,
198â†’  }
199â†’}
200â†’
201â†’function isValidInterval(value: string): boolean {
202â†’  const match = value.trim().toLowerCase().match(/^(\d+)\s*(s|m|h)$/)
203â†’  if (!match) return false
204â†’  return parseInt(match[1]!, 10) > 0
205â†’}
206â†’

  1â†’/**
  2â†’ * Manage ~/.memorytree/alerts.json â€” append, dedup, threshold, display.
  3â†’ * Port of scripts/_alert_utils.py
  4â†’ */
  5â†’
  6â†’import { existsSync, mkdirSync, readFileSync, unlinkSync, writeFileSync } from 'node:fs'
  7â†’import { homedir } from 'node:os'
  8â†’import { dirname, resolve } from 'node:path'
  9â†’
 10â†’// ---------------------------------------------------------------------------
 11â†’// Constants
 12â†’// ---------------------------------------------------------------------------
 13â†’
 14â†’export const MAX_ALERTS = 100
 15â†’
 16â†’export const ALERT_TYPES: ReadonlySet<string> = new Set([
 17â†’  'no_remote',
 18â†’  'sensitive_match',
 19â†’  'push_failed',
 20â†’  'lock_held',
 21â†’])
 22â†’
 23â†’export const FAILURE_THRESHOLD = 3
 24â†’
 25â†’// ---------------------------------------------------------------------------
 26â†’// Types
 27â†’// ---------------------------------------------------------------------------
 28â†’
 29â†’export interface Alert {
 30â†’  readonly timestamp: string
 31â†’  readonly project: string
 32â†’  readonly type: string
 33â†’  readonly message: string
 34â†’  readonly count: number
 35â†’  readonly [key: string]: unknown
 36â†’}
 37â†’
 38â†’// ---------------------------------------------------------------------------
 39â†’// Path helpers
 40â†’// ---------------------------------------------------------------------------
 41â†’
 42â†’export function alertsPath(): string {
 43â†’  return resolve(homedir(), '.memorytree', 'alerts.json')
 44â†’}
 45â†’
 46â†’function failureStatePath(): string {
 47â†’  return resolve(homedir(), '.memorytree', 'failure_counts.json')
 48â†’}
 49â†’
 50â†’// ---------------------------------------------------------------------------
 51â†’// Timestamp helper (self-contained â€” no cross-module dependency)
 52â†’// ---------------------------------------------------------------------------
 53â†’
 54â†’function utcTimestamp(): string {
 55â†’  return new Date().toISOString().replace(/\.\d{3}Z$/, 'Z')
 56â†’}
 57â†’
 58â†’// ---------------------------------------------------------------------------
 59â†’// Read / Write alerts
 60â†’// ---------------------------------------------------------------------------
 61â†’
 62â†’export function readAlerts(): readonly Alert[] {
 63â†’  const path = alertsPath()
 64â†’  if (!existsSync(path)) {
 65â†’    return []
 66â†’  }
 67â†’  try {
 68â†’    const text = readFileSync(path, 'utf-8')
 69â†’    const data: unknown = JSON.parse(text)
 70â†’    if (!Array.isArray(data)) {
 71â†’      return []
 72â†’    }
 73â†’    return data as Alert[]
 74â†’  } catch {
 75â†’    return []
 76â†’  }
 77â†’}
 78â†’
 79â†’export function writeAlert(project: string, alertType: string, message: string): void {
 80â†’  const alerts = readAlerts()
 81â†’  const now = utcTimestamp()
 82â†’
 83â†’  let found = false
 84â†’  const updated: Alert[] = []
 85â†’
 86â†’  for (const alert of alerts) {
 87â†’    if (alert.project === project && alert.type === alertType) {
 88â†’      updated.push({
 89â†’        ...alert,
 90â†’        timestamp: now,
 91â†’        message,
 92â†’        count: (alert.count ?? 1) + 1,
 93â†’      })
 94â†’      found = true
 95â†’    } else {
 96â†’      updated.push({ ...alert })
 97â†’    }
 98â†’  }
 99â†’
100â†’  if (!found) {
101â†’    updated.push({ timestamp: now, project, type: alertType, message, count: 1 })
102â†’  }
103â†’
104â†’  const trimmed = updated.length > MAX_ALERTS
105â†’    ? updated.slice(updated.length - MAX_ALERTS)
106â†’    : updated
107â†’
108â†’  saveAlerts(trimmed)
109â†’}
110â†’
111â†’// ---------------------------------------------------------------------------
112â†’// Threshold-based writes
113â†’// ---------------------------------------------------------------------------
114â†’
115â†’export function writeAlertWithThreshold(
116â†’  project: string,
117â†’  alertType: string,
118â†’  message: string,
119â†’): void {
120â†’  const counts = readFailureCounts()
121â†’  const key = `${project}::${alertType}`
122â†’  const current = ((counts[key] as number | undefined) ?? 0) + 1
123â†’  const newCounts: Record<string, number> = { ...counts, [key]: current }
124â†’  saveFailureCounts(newCounts)
125â†’
126â†’  if (current >= FAILURE_THRESHOLD) {
127â†’    writeAlert(project, alertType, message)
128â†’  }
129â†’}
130â†’
131â†’export function resetFailureCount(project: string, alertType: string): void {
132â†’  const counts = readFailureCounts()
133â†’  const key = `${project}::${alertType}`
134â†’  if (key in counts) {
135â†’    const newCounts: Record<string, number> = {}
136â†’    for (const [k, v] of Object.entries(counts)) {
137â†’      if (k !== key) {
138â†’        newCounts[k] = v
139â†’      }
140â†’    }
141â†’    saveFailureCounts(newCounts)
142â†’  }
143â†’}
144â†’
145â†’// ---------------------------------------------------------------------------
146â†’// Clear
147â†’// ---------------------------------------------------------------------------
148â†’
149â†’export function clearAlerts(): void {
150â†’  const path = alertsPath()
151â†’  if (existsSync(path)) {
152â†’    try {
153â†’      unlinkSync(path)
154â†’    } catch {
155â†’      // Silently ignore removal errors (matches Python behaviour)
156â†’    }
157â†’  }
158â†’}
159â†’
160â†’// ---------------------------------------------------------------------------
161â†’// Display
162â†’// ---------------------------------------------------------------------------
163â†’
164â†’export function formatAlertsForDisplay(alerts: readonly Record<string, unknown>[]): string {
165â†’  if (alerts.length === 0) {
166â†’    return ''
167â†’  }
168â†’  const lines: string[] = []
169â†’  for (const alert of alerts) {
170â†’    const count = typeof alert['count'] === 'number' ? alert['count'] : 1
171â†’    const countSuffix = count > 1 ? ` (x${String(count)})` : ''
172â†’    const type = typeof alert['type'] === 'string' ? alert['type'] : 'unknown'
173â†’    const project = typeof alert['project'] === 'string' ? alert['project'] : '?'
174â†’    const message = typeof alert['message'] === 'string' ? alert['message'] : ''
175â†’    lines.push(`  [${type}] ${project}: ${message}${countSuffix}`)
176â†’  }
177â†’  return lines.join('\n')
178â†’}
179â†’
180â†’// ---------------------------------------------------------------------------
181â†’// Internal â€” alerts persistence
182â†’// ---------------------------------------------------------------------------
183â†’
184â†’function saveAlerts(alerts: readonly Alert[]): void {
185â†’  const path = alertsPath()
186â†’  mkdirSync(dirname(path), { recursive: true })
187â†’  writeFileSync(path, JSON.stringify(alerts, null, 2) + '\n', 'utf-8')
188â†’}
189â†’
190â†’// ---------------------------------------------------------------------------
191â†’// Internal â€” failure counts persistence
192â†’// ---------------------------------------------------------------------------
193â†’
194â†’function readFailureCounts(): Record<string, number> {
195â†’  const path = failureStatePath()
196â†’  if (!existsSync(path)) {
197â†’    return {}
198â†’  }
199â†’  try {
200â†’    const text = readFileSync(path, 'utf-8')
201â†’    const data: unknown = JSON.parse(text)
202â†’    if (data === null || typeof data !== 'object' || Array.isArray(data)) {
203â†’      return {}
204â†’    }
205â†’    return data as Record<string, number>
206â†’  } catch {
207â†’    return {}
208â†’  }
209â†’}
210â†’
211â†’function saveFailureCounts(counts: Record<string, number>): void {
212â†’  const path = failureStatePath()
213â†’  mkdirSync(dirname(path), { recursive: true })
214â†’  writeFileSync(path, JSON.stringify(counts, null, 2) + '\n', 'utf-8')
215â†’}
