  1â†’/**
  2â†’ * PID-based lock file for heartbeat single-instance enforcement.
  3â†’ * Port of scripts/_lock_utils.py
  4â†’ */
  5â†’
  6â†’import {
  7â†’  closeSync,
  8â†’  constants,
  9â†’  existsSync,
 10â†’  mkdirSync,
 11â†’  openSync,
 12â†’  readFileSync,
 13â†’  unlinkSync,
 14â†’  writeSync,
 15â†’} from 'node:fs'
 16â†’import { homedir } from 'node:os'
 17â†’import { dirname, resolve } from 'node:path'
 18â†’import { execFileSync } from 'node:child_process'
 19â†’
 20â†’// ---------------------------------------------------------------------------
 21â†’// Path helpers
 22â†’// ---------------------------------------------------------------------------
 23â†’
 24â†’export function lockPath(): string {
 25â†’  return resolve(homedir(), '.memorytree', 'heartbeat.lock')
 26â†’}
 27â†’
 28â†’// ---------------------------------------------------------------------------
 29â†’// Lock acquisition
 30â†’// ---------------------------------------------------------------------------
 31â†’
 32â†’/**
 33â†’ * Try to acquire the heartbeat lock. Returns `true` on success.
 34â†’ *
 35â†’ * If the lock file already exists, the stored PID is checked:
 36â†’ * - alive process  -> return false (already running)
 37â†’ * - dead process   -> reclaim the stale lock
 38â†’ * - corrupt file   -> remove and retry
 39â†’ *
 40â†’ * Uses `O_CREAT | O_EXCL` to prevent TOCTOU races.
 41â†’ */
 42â†’export function acquireLock(): boolean {
 43â†’  const path = lockPath()
 44â†’  mkdirSync(dirname(path), { recursive: true })
 45â†’
 46â†’  if (existsSync(path)) {
 47â†’    let storedPid: number | undefined
 48â†’    try {
 49â†’      const raw = readFileSync(path, 'utf-8').trim()
 50â†’      storedPid = parseInt(raw, 10)
 51â†’      if (!Number.isFinite(storedPid)) {
 52â†’        storedPid = undefined
 53â†’      }
 54â†’    } catch {
 55â†’      // Corrupt lock file â€” treat as stale
 56â†’      storedPid = undefined
 57â†’    }
 58â†’
 59â†’    if (storedPid === undefined) {
 60â†’      // Corrupt or unreadable lock file â€” remove it
 61â†’      removeLockFile(path)
 62â†’    } else {
 63â†’      if (isProcessAlive(storedPid)) {
 64â†’        return false
 65â†’      }
 66â†’      // Stale lock from a dead process â€” reclaim
 67â†’      removeLockFile(path)
 68â†’    }
 69â†’  }
 70â†’
 71â†’  // Use exclusive create to prevent TOCTOU race
 72â†’  try {
 73â†’    const fd = openSync(path, constants.O_CREAT | constants.O_EXCL | constants.O_WRONLY)
 74â†’    const pidBytes = Buffer.from(String(process.pid), 'utf-8')
 75â†’    writeSync(fd, pidBytes)
 76â†’    closeSync(fd)
 77â†’  } catch {
 78â†’    // Another process created the lock between our check and create,
 79â†’    // or an OS-level I/O error occurred.
 80â†’    return false
 81â†’  }
 82â†’  return true
 83â†’}
 84â†’
 85â†’// ---------------------------------------------------------------------------
 86â†’// Lock release
 87â†’// ---------------------------------------------------------------------------
 88â†’
 89â†’/** Release the heartbeat lock. */
 90â†’export function releaseLock(): void {
 91â†’  removeLockFile(lockPath())
 92â†’}
 93â†’
 94â†’// ---------------------------------------------------------------------------
 95â†’// Lock inspection
 96â†’// ---------------------------------------------------------------------------
 97â†’
 98â†’/** Read the PID from the lock file, or `null` if not locked / corrupt. */
 99â†’export function readLockPid(): number | null {
100â†’  const path = lockPath()
101â†’  if (!existsSync(path)) {
102â†’    return null
103â†’  }
104â†’  try {
105â†’    const raw = readFileSync(path, 'utf-8').trim()
106â†’    const pid = parseInt(raw, 10)
107â†’    return Number.isFinite(pid) ? pid : null
108â†’  } catch {
109â†’    return null
110â†’  }
111â†’}
112â†’
113â†’// ---------------------------------------------------------------------------
114â†’// Process liveness
115â†’// ---------------------------------------------------------------------------
116â†’
117â†’/** Check whether a process with the given PID is still running. */
118â†’export function isProcessAlive(pid: number): boolean {
119â†’  if (pid <= 0) {
120â†’    return false
121â†’  }
122â†’  if (process.platform === 'win32') {
123â†’    return isProcessAliveWindows(pid)
124â†’  }
125â†’  return isProcessAliveUnix(pid)
126â†’}
127â†’
128â†’function isProcessAliveUnix(pid: number): boolean {
129â†’  try {
130â†’    process.kill(pid, 0)
131â†’    return true
132â†’  } catch (err: unknown) {
133â†’    if (err instanceof Error && 'code' in err) {
134â†’      // EPERM means the process exists but we lack permission to signal it
135â†’      if ((err as NodeJS.ErrnoException).code === 'EPERM') {
136â†’        return true
137â†’      }
138â†’    }
139â†’    // ESRCH or any other error means the process does not exist
140â†’    return false
141â†’  }
142â†’}
143â†’
144â†’function isProcessAliveWindows(pid: number): boolean {
145â†’  try {
146â†’    const output = execFileSync('tasklist', ['/FI', `PID eq ${pid}`, '/NH'], {
147â†’      encoding: 'utf-8',
148â†’      timeout: 5000,
149â†’      windowsHide: true,
150â†’    })
151â†’    // tasklist prints "INFO: No tasks are running..." when no match is found.
152â†’    // Otherwise, the output contains the PID as a number in the line.
153â†’    return output.includes(String(pid))
154â†’  } catch {
155â†’    return false
156â†’  }
157â†’}
158â†’
159â†’// ---------------------------------------------------------------------------
160â†’// Internal helpers
161â†’// ---------------------------------------------------------------------------
162â†’
163â†’function removeLockFile(path: string): void {
164â†’  try {
165â†’    unlinkSync(path)
166â†’  } catch {
167â†’    // Ignore errors â€” file may already be gone
168â†’  }
169â†’}
170â†’

